import java.io.IOException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String encodedUserInput = encodeForHtml(userInput);

        String htmlResponse = "<html><body>";
        htmlResponse += "<h1>User Input: " + encodedUserInput + "</h1>"; // Properly encoding user input before including in the response
        htmlResponse += "</body></html>";

        response.getWriter().println(htmlResponse);
    }

    private String encodeForHtml(String input) {
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
